export const QUIZ_QUESTIONS: QuizSet[] = [
  {
    module_id: 1,
    questions: [
      { id: 'q1_1', question: 'What does "extreme poverty" mean according to the World Bank?', options: ['Living on less than $2.15 per day', 'Not owning a house', 'Living without a smartphone', 'Earning less than $10 per day'], correct: 0, explanation: 'The World Bank defines extreme poverty as living on less than $2.15 per day — a very small amount that cannot cover basic needs like food, shelter, and healthcare.' },
      { id: 'q1_2', question: 'Which group is MOST affected by poverty in Africa?', options: ['Business owners', 'Girls and women', 'Government workers', 'Urban workers'], correct: 1, explanation: 'Girls and women are disproportionately affected by poverty. They face barriers like being pulled from school, early marriage, and discrimination that keep them and their families in poverty.' },
      { id: 'q1_3', question: 'What does "financial literacy" mean?', options: ['Being able to read books about money', 'Having knowledge and skills to manage money well', 'Working in a bank', 'Studying economics at university'], correct: 1, explanation: 'Financial literacy means having the knowledge and skills to make informed decisions about managing, saving, and investing money. It is a crucial tool for escaping poverty.' },
      { id: 'q1_4', question: 'Maria stays in school instead of getting married at 15. How does this help fight poverty in her community?', options: ['It does not help — she is just one person', 'An educated Maria will earn more, invest in her family, and inspire others', 'It helps only if she studies business', 'It helps only if she becomes a doctor'], correct: 1, explanation: 'Education multiplies benefits. An educated Maria earns more, makes informed decisions, invests in her children\'s education, and becomes a role model — lifting her whole community.' },
      { id: 'q1_5', question: 'What is SDG 1 about?', options: ['Zero Hunger', 'Quality Education', 'No Poverty', 'Gender Equality'], correct: 2, explanation: 'SDG 1 is "No Poverty" — the goal to end poverty in all its forms everywhere by 2030.' },
      { id: 'q1_6', question: 'Which of the following is an example of the "cycle of poverty"?', options: ['A girl drops out of school due to poverty, cannot get a good job, remains poor', 'A rich family saves money in a bank', 'A government builds new roads', 'A company pays good salaries'], correct: 0, explanation: 'The cycle of poverty describes how poverty creates conditions (like dropping out of school) that make it harder to escape poverty, trapping families across generations.' },
      { id: 'q1_7', question: 'Amara joins a savings group with other girls at school. What SDG does this relate to?', options: ['SDG 13: Climate Action', 'SDG 1: No Poverty', 'SDG 14: Life Below Water', 'SDG 11: Sustainable Cities'], correct: 1, explanation: 'Joining a savings group builds financial skills and capital — directly addressing SDG 1 (No Poverty) by empowering girls with financial tools to improve their economic situation.' },
      { id: 'q1_8', question: 'What is entrepreneurship?', options: ['Working for the government', 'Starting and running your own business', 'Studying at university', 'Volunteering in a community'], correct: 1, explanation: 'Entrepreneurship means identifying a problem, creating a business solution, and running that business. It is a powerful path to economic independence, especially for girls and women.' },
      { id: 'q1_9', question: 'How many people worldwide live in extreme poverty today?', options: ['About 70 million', 'About 700 million', 'About 7 billion', 'About 70 billion'], correct: 1, explanation: 'Approximately 700 million people still live in extreme poverty globally — surviving on less than $2.15 per day. This is about 9% of the world\'s population.' },
      { id: 'q1_10', question: 'What is the MOST powerful tool for escaping poverty, according to SDG 1?', options: ['Winning the lottery', 'Education', 'Moving to a city', 'Having many children'], correct: 1, explanation: 'Education is consistently identified as the most powerful tool for escaping poverty. Educated individuals earn more, make healthier decisions, and contribute more to their communities\' development.' }
    ]
  },
  {
    module_id: 2,
    questions: [
      { id: 'q2_1', question: 'What is the difference between hunger and malnutrition?', options: ['They are exactly the same thing', 'Hunger means not enough food; malnutrition means not the right nutrients', 'Malnutrition is only for children', 'Hunger is only in Africa'], correct: 1, explanation: 'Hunger means not having enough food calories. Malnutrition means not getting the right nutrients — someone can eat every day but still be malnourished if their diet lacks iron, vitamins, and protein.' },
      { id: 'q2_2', question: 'How much of Africa\'s food is produced by women?', options: ['About 10%', 'About 30%', 'More than 60%', 'About 80%'], correct: 2, explanation: 'Women produce more than 60% of Africa\'s food, yet they often have less access to land, tools, training, and credit than men. Empowering women farmers is key to food security.' },
      { id: 'q2_3', question: 'What is "sustainable farming"?', options: ['Farming that uses lots of chemicals for maximum output', 'Farming that protects the environment and can continue for future generations', 'Farming only in cities', 'Farming that exports all produce abroad'], correct: 1, explanation: 'Sustainable farming means growing food in ways that protect soil health, water resources, and biodiversity — ensuring future generations can also grow food from the same land.' },
      { id: 'q2_4', question: 'A girl in a village learns that eating "rainbow foods" (colorful fruits and vegetables) improves her family\'s nutrition. What SDG is she supporting?', options: ['SDG 7', 'SDG 2: Zero Hunger', 'SDG 15', 'SDG 9'], correct: 1, explanation: 'Learning about nutrition and applying it to improve family health directly supports SDG 2 (Zero Hunger), which includes improving nutrition quality, not just food quantity.' },
      { id: 'q2_5', question: 'What does SDG 2 aim to achieve?', options: ['End deforestation', 'End hunger and improve nutrition', 'Provide clean water for all', 'Reduce inequality'], correct: 1, explanation: 'SDG 2 is "Zero Hunger" — aiming to end hunger, achieve food security, improve nutrition, and promote sustainable agriculture for everyone by 2030.' },
      { id: 'q2_6', question: 'Why might girls in some communities receive less food than boys?', options: ['Girls need fewer calories', 'Cultural practices sometimes prioritize feeding boys first', 'Girls prefer different foods', 'Girls eat more slowly'], correct: 1, explanation: 'In some communities, cultural practices give boys priority access to food, especially nutritious foods. This contributes to higher rates of malnutrition in girls and women.' },
      { id: 'q2_7', question: 'What is "intercropping"?', options: ['Farming between two countries', 'Growing different crops together to improve soil and food variety', 'Importing food from other countries', 'Using machines to plant seeds faster'], correct: 1, explanation: 'Intercropping means growing two or more crops together — like beans alongside maize. The beans fix nitrogen in the soil, improving fertility for the maize, and the farmer gets two crops at once.' },
      { id: 'q2_8', question: 'How does access to clean water near a village help fight hunger?', options: ['It doesn\'t — water and food are separate issues', 'Girls spend less time collecting water and can instead help grow and prepare food', 'It automatically grows crops', 'It removes the need for farming'], correct: 1, explanation: 'When water is close to home, girls and women spend less time fetching it. That time can be used for farming, food preparation, education, and income generation — all contributing to food security.' },
      { id: 'q2_9', question: 'About how many people in the world go to bed hungry each night?', options: ['About 8 million', 'About 80 million', 'About 828 million', 'About 8 billion'], correct: 2, explanation: 'Approximately 828 million people — more than 10% of the world\'s population — experience hunger daily. This is why SDG 2 is urgent and requires global action.' },
      { id: 'q2_10', question: 'What is a "school garden" and how does it support SDG 2?', options: ['A decorative garden with flowers', 'A garden where students grow food, learn nutrition, and contribute to school meals', 'A garden only for science experiments', 'A garden that the school sells for profit'], correct: 1, explanation: 'A school garden is where students grow vegetables and fruits for school meals and their own consumption. It teaches nutrition, agricultural skills, and provides healthier food — directly supporting SDG 2.' }
    ]
  },
  {
    module_id: 3,
    questions: [
      { id: 'q3_1', question: 'What does "good health and well-being" mean according to SDG 3?', options: ['Only physical health — being free from disease', 'Physical, mental, and emotional well-being for everyone', 'Having access to expensive hospitals', 'Only mental health care'], correct: 1, explanation: 'SDG 3 defines good health broadly as physical, mental, and emotional well-being — not just the absence of disease. This includes mental health, reproductive health, and access to quality healthcare.' },
      { id: 'q3_2', question: 'Why is menstrual health education important for girls?', options: ['It is not important — periods are private', 'It helps girls manage their periods confidently and attend school every month', 'It is only for nurses and doctors', 'It is only important in cities'], correct: 1, explanation: 'Menstrual health education helps girls understand their bodies, manage periods safely, and attend school during their period. Without this knowledge, many girls miss school days every month.' },
      { id: 'q3_3', question: 'What is mental health?', options: ['Only being diagnosed with a mental illness', 'Our emotional, psychological, and social well-being — how we think, feel, and relate to others', 'Being happy all the time', 'Only relevant for adults'], correct: 1, explanation: 'Mental health encompasses our emotional, psychological, and social well-being. It affects how we think, feel, make decisions, and relate to others. Good mental health is essential at every age.' },
      { id: 'q3_4', question: 'Young women make up what percentage of new HIV infections among 15-24 year olds in sub-Saharan Africa?', options: ['About 15%', 'About 30%', 'More than 63%', 'About 50%'], correct: 2, explanation: 'Young women in sub-Saharan Africa make up more than 63% of new HIV infections in the 15-24 age group — making HIV/AIDS education and prevention critically important for this group.' },
      { id: 'q3_5', question: 'If a friend tells you she is feeling very sad and hopeless every day, what is the best response?', options: ['Tell her to just be happy', 'Listen with empathy and encourage her to speak with a trusted adult or counselor', 'Ignore it — she\'ll get over it', 'Tell everyone at school about it'], correct: 1, explanation: 'When someone shares feelings of persistent sadness and hopelessness, the best response is empathetic listening and encouraging them to seek help from a trusted adult, counselor, or health professional.' },
      { id: 'q3_6', question: 'What is HIV?', options: ['A type of malaria', 'A virus that attacks the immune system, making it harder to fight infections', 'A vitamin deficiency', 'A mental health condition'], correct: 1, explanation: 'HIV (Human Immunodeficiency Virus) attacks the immune system, gradually weakening the body\'s ability to fight infections and diseases. With modern treatment (ARVs), people with HIV can live long, healthy lives.' },
      { id: 'q3_7', question: 'What makes a school truly supportive of girls\' health?', options: ['Having a uniform policy', 'Separate clean toilets for girls, clean water, menstrual hygiene products, and health education', 'Having a computer lab', 'Playing sports every day'], correct: 1, explanation: 'A girl-friendly school provides separate, private toilets for girls with handwashing facilities, access to menstrual hygiene products, and health education — enabling girls to attend every school day comfortably.' },
      { id: 'q3_8', question: 'Seeking help for mental health challenges is...', options: ['A sign of weakness and something to be ashamed of', 'An act of courage and self-care', 'Only necessary if you are "crazy"', 'Something to hide from family'], correct: 1, explanation: 'Seeking mental health support is an act of courage and self-awareness. Mental health challenges are common, treatable medical conditions — seeking help is as important as seeing a doctor for physical illness.' },
      { id: 'q3_9', question: 'Why do girls in some African communities miss school during their periods?', options: ['They don\'t want to learn', 'Lack of sanitary products, private toilets, and cultural stigma about menstruation', 'Periods make them unable to study', 'School rules forbid it'], correct: 1, explanation: 'Many girls miss school during their periods due to lack of affordable sanitary products, inadequate private toilet facilities at school, pain, and cultural stigma that makes discussing periods taboo.' },
      { id: 'q3_10', question: 'SDG 3 aims to reduce maternal mortality. "Maternal mortality" means...', options: ['Children dying before age 5', 'Deaths of mothers during pregnancy or childbirth', 'Women living past age 80', 'Deaths from infectious diseases'], correct: 1, explanation: 'Maternal mortality refers to deaths of women during pregnancy, childbirth, or within 42 days of delivery. Africa has the highest maternal mortality rates globally, making this a critical SDG 3 target.' }
    ]
  },
  {
    module_id: 4,
    questions: [
      { id: 'q4_1', question: 'SDG 4 calls for "quality education." What makes education "quality"?', options: ['Having expensive buildings and equipment', 'Learning that is relevant, engaging, and equips students with real skills for life', 'Passing as many students as possible', 'Teaching only mathematics and English'], correct: 1, explanation: 'Quality education is meaningful, relevant to students\' real lives, inclusive, and equips learners with knowledge, skills, values, and attitudes needed to thrive and contribute to society.' },
      { id: 'q4_2', question: 'When a girl receives quality education, which of the following happens?', options: ['Only she benefits personally', 'She, her family, her community, and her country all benefit', 'Only the economy benefits', 'Only future generations benefit'], correct: 1, explanation: 'Research consistently shows that educated girls marry later, have healthier children, earn more income, invest in their communities, and contribute to national economic growth — benefits that multiply across generations.' },
      { id: 'q4_3', question: 'What does "STEM" stand for?', options: ['Schools, Teachers, Education, Mathematics', 'Science, Technology, Engineering, and Mathematics', 'Society, Training, Environment, Mentorship', 'Sports, Technology, Entrepreneurship, Management'], correct: 1, explanation: 'STEM stands for Science, Technology, Engineering, and Mathematics. These are among the fastest-growing career fields globally, and African girls who pursue STEM can solve Africa\'s unique challenges.' },
      { id: 'q4_4', question: 'A girl walks 10km to school every day, which takes 2 hours each way. This is an example of...', options: ['Good fitness training', 'A barrier to education that needs to be addressed', 'Normal life that everyone faces', 'An opportunity for exercise'], correct: 1, explanation: 'Long, dangerous distances to school are a major barrier to girls\' education, especially in rural Africa. This barrier reduces attendance, increases safety risks, and often leads girls to drop out.' },
      { id: 'q4_5', question: 'In Rwanda, what was linked to the increase in women in parliament to 61%?', options: ['A new constitution requiring female MPs', 'Investment in girls\' education over many years', 'Foreign aid programs', 'Women forming their own political party'], correct: 1, explanation: 'Rwanda\'s high female representation in parliament (61% — world\'s highest) is directly linked to decades of investment in girls\' education, creating a generation of educated, empowered women who sought and won leadership roles.' },
      { id: 'q4_6', question: 'What is "early marriage" and why does it harm girls\' education?', options: ['Marriage before age 20 — it doesn\'t affect education', 'Marriage before age 18 — it usually ends girls\' schooling and limits their future opportunities', 'Marriage arranged by parents — it helps girls find stable homes', 'Marriage during university — it improves stability'], correct: 1, explanation: 'Child/early marriage (before 18) almost always ends girls\' education as they take on domestic and maternal responsibilities too early, permanently limiting their opportunities and often trapping them in poverty.' },
      { id: 'q4_7', question: 'How does a female teacher in a rural school affect girls?', options: ['It makes no difference who teaches', 'She serves as a living proof that women can be professionals, inspiring girls to dream bigger', 'She is less qualified than male teachers', 'She only helps with feminine subjects'], correct: 1, explanation: 'Female teachers are powerful role models, especially in communities where girls rarely see women in professional roles. Seeing a woman who is educated, earns income, and is respected as a teacher inspires girls to envision similar futures.' },
      { id: 'q4_8', question: 'What is "lifelong learning"?', options: ['Learning only until you finish school', 'The idea that education and learning continue throughout a person\'s entire life', 'Learning through travel only', 'Reading books every day without a purpose'], correct: 1, explanation: 'Lifelong learning means continuing to learn, grow, and develop skills throughout your entire life — not just during formal schooling. In a rapidly changing world, this is essential for adapting and thriving.' },
      { id: 'q4_9', question: 'An educated girl is how many times less likely to be infected with HIV?', options: ['The same risk as uneducated girls', 'Twice as likely', 'Three times less likely', 'Equally at risk'], correct: 2, explanation: 'Studies show that educated girls are 3 times less likely to be infected with HIV. Education provides health knowledge, economic alternatives, and the confidence to protect themselves and make informed decisions.' },
      { id: 'q4_10', question: 'What does "inclusive education" mean?', options: ['Education only for the smartest students', 'Education that includes and accommodates all students regardless of gender, disability, or background', 'Education that includes sports and art', 'Education that includes adult learners only'], correct: 1, explanation: 'Inclusive education means that all children — regardless of disability, gender, ethnicity, religion, or economic background — have equal access to quality learning in the same school environment with appropriate support.' }
    ]
  },
  {
    module_id: 5,
    questions: [
      { id: 'q5_1', question: 'What does "gender equality" mean?', options: ['Girls and boys being exactly the same', 'All genders having equal rights, opportunities, and respect', 'Women having more rights than men', 'Men providing for women'], correct: 1, explanation: 'Gender equality means that all genders — women, men, girls, boys, and others — have equal rights, equal opportunities, equal access to resources, and are treated with equal respect and dignity.' },
      { id: 'q5_2', question: 'What is "intersectionality"?', options: ['A road junction', 'When multiple forms of disadvantage (gender, poverty, race, disability) combine to affect someone', 'A new feminist movement', 'When two laws conflict'], correct: 1, explanation: 'Intersectionality describes how different aspects of a person\'s identity (gender, race, class, disability) overlap and interact, creating unique combinations of privilege or disadvantage.' },
      { id: 'q5_3', question: 'What is Female Genital Mutilation/Cutting (FGM/C)?', options: ['A traditional medical procedure', 'A harmful practice involving partial or total removal of external female genitalia that violates girls\' rights and health', 'A female beauty practice', 'An initiation into adulthood that has no health consequences'], correct: 1, explanation: 'FGM/C is the partial or total removal of external female genitalia for non-medical reasons. It is a human rights violation that causes severe pain, health complications, and psychological trauma with no health benefits.' },
      { id: 'q5_4', question: 'Why is "child marriage" harmful to girls?', options: ['It is beneficial because it provides security', 'It ends education, endangers health through early pregnancy, and limits girls\' life choices and freedom', 'It is only harmful in cities', 'It is not harmful if the girl agrees'], correct: 1, explanation: 'Child marriage ends girls\' education, puts their health at risk through early pregnancy (the leading cause of death for 15-19 year old girls globally), removes their freedom, and violates their right to choose their own path.' },
      { id: 'q5_5', question: 'How many girls and women globally are affected by FGM/C?', options: ['About 200,000', 'About 2 million', 'More than 200 million', 'About 20 million'], correct: 2, explanation: 'Over 200 million girls and women worldwide have undergone FGM/C. About 3 million girls are at risk of FGM/C every year. It is practiced in 30 countries, primarily in Africa, but also in parts of the Middle East and Asia.' },
      { id: 'q5_6', question: 'A girl is told she cannot study mathematics because "it\'s for boys." This is an example of...', options: ['Realistic career guidance', 'Gender discrimination and stereotype', 'Good parenting', 'Cultural respect'], correct: 1, explanation: 'Telling a girl she cannot or should not study certain subjects based on gender is gender discrimination based on stereotypes. It limits girls\' potential and career options based on false assumptions about gender.' },
      { id: 'q5_7', question: 'Which African woman was the FIRST to win the Nobel Peace Prize?', options: ['Wangari Maathai of Kenya', 'Ellen Johnson Sirleaf of Liberia', 'Leymah Gbowee of Liberia', 'Ngozi Okonjo-Iweala of Nigeria'], correct: 0, explanation: 'Wangari Maathai of Kenya was the first African woman to win the Nobel Peace Prize in 2004, recognized for her contribution to sustainable development, democracy, and peace through the Green Belt Movement.' },
      { id: 'q5_8', question: 'When women are equally represented in government, what typically happens?', options: ['Nothing changes in policy', 'Policies better reflect the needs of women, children, and marginalized groups', 'Government becomes less efficient', 'Men\'s rights are reduced'], correct: 1, explanation: 'Research consistently shows that when women are equally represented in government, policies more often address women\'s and children\'s needs, social spending increases, and governance quality improves.' },
      { id: 'q5_9', question: 'Gender equality is beneficial to...', options: ['Only women and girls', 'Only developing countries', 'Everyone — women, men, families, communities, and economies', 'Only future generations'], correct: 2, explanation: 'Gender equality benefits everyone. When women and girls have equal rights and opportunities, economies grow, families are healthier, children are better educated, and communities are more peaceful and prosperous.' },
      { id: 'q5_10', question: 'What was significant about Dr. Ngozi Okonjo-Iweala\'s appointment at the World Trade Organization?', options: ['She was the first African man to lead it', 'She was the first woman and first African to lead the WTO', 'She was the youngest WTO leader', 'She was the longest-serving WTO leader'], correct: 1, explanation: 'Dr. Ngozi Okonjo-Iweala became the first woman and first African to lead the World Trade Organization in 2021 — breaking two historic barriers at once and demonstrating that African women belong in the highest global leadership positions.' }
    ]
  },
  {
    module_id: 6,
    questions: [
      { id: 'q6_1', question: 'How many people globally lack access to safe drinking water?', options: ['About 220 million', 'About 2.2 billion', 'About 220,000', 'About 22 million'], correct: 1, explanation: '2.2 billion people — about 29% of the world\'s population — lack access to safe drinking water. Billions more lack basic sanitation services, threatening health and dignity.' },
      { id: 'q6_2', question: 'What is the "water burden" and who carries it most in Africa?', options: ['The cost of water bills — paid by governments', 'The time and effort spent collecting water — carried mostly by women and girls', 'The weight of carrying water — shared equally by families', 'Environmental damage from water extraction — addressed by companies'], correct: 1, explanation: 'The "water burden" refers to the time and physical effort required to collect water from distant sources. In Africa, this burden falls almost entirely on women and girls, consuming hours daily that could be spent on education and income.' },
      { id: 'q6_3', question: 'When a school builds separate toilets for girls, what typically happens?', options: ['Nothing changes significantly', 'Girls\' attendance improves, especially during their periods', 'Boys\' attendance decreases', 'Toilet maintenance costs rise dramatically'], correct: 1, explanation: 'When schools build private, clean toilets for girls with handwashing facilities, girls\' attendance improves significantly — especially during menstruation when girls with no private facilities previously stayed home.' },
      { id: 'q6_4', question: 'What is "WASH" in the context of SDG 6?', options: ['Washing machines in schools', 'Water, Sanitation, and Hygiene — a framework for clean water and sanitation programs', 'Water and sanitation hygiene testing', 'Washing and sanitation habits'], correct: 1, explanation: 'WASH stands for Water, Sanitation, and Hygiene. WASH programs in schools and communities work to provide clean water sources, proper toilets, and hygiene education to improve health and school attendance.' },
      { id: 'q6_5', question: 'In Ethiopia\'s Amhara region, what happened to girls\' school attendance when water points were built nearby?', options: ['Attendance decreased', 'Attendance increased by 12% and grades improved', 'Attendance stayed the same', 'Only boys\' attendance improved'], correct: 1, explanation: 'When water points were built within 30 minutes of villages in Ethiopia\'s Amhara region, girls\' school attendance increased by 12% because they no longer had to spend hours fetching water instead of attending school.' },
      { id: 'q6_6', question: 'What is "rainwater harvesting"?', options: ['Collecting rain in buckets for decoration', 'Systematically collecting and storing rainwater for future use in drinking, cooking, and irrigation', 'Predicting rainfall patterns', 'Dancing in the rain for celebrations'], correct: 1, explanation: 'Rainwater harvesting means collecting rainwater from rooftops or other surfaces and storing it in tanks or underground cisterns for later use. It is an affordable, low-tech solution to water scarcity in many African communities.' },
      { id: 'q6_7', question: 'How does lack of clean water affect community health?', options: ['It has no significant health effects', 'It causes waterborne diseases like cholera, typhoid, and diarrhea that kill millions each year', 'It only affects those who drink river water', 'It mainly causes skin problems'], correct: 1, explanation: 'Unsafe water causes waterborne diseases like cholera, typhoid, dysentery, and diarrhea that kill 2 million people annually, mostly children under 5. Clean water is one of the most fundamental determinants of public health.' },
      { id: 'q6_8', question: 'Climate change affects water access by...', options: ['Always providing more rainfall to Africa', 'Making rainfall less predictable — some areas get floods, others face drought', 'Having no significant effect on water availability', 'Improving water quality in rivers'], correct: 1, explanation: 'Climate change disrupts water cycles, making rainfall less predictable. Some areas experience more intense floods while others face longer, more severe droughts — threatening water security for billions of people.' },
      { id: 'q6_9', question: 'A simple action girls can take to support SDG 6 in their school is:', options: ['Demanding the school buys bottled water', 'Reporting leaking taps, keeping toilets clean, and teaching peers about water conservation', 'Using more water to show abundance', 'Not using the school toilet'], correct: 1, explanation: 'Girls can support SDG 6 by reporting leaking infrastructure, keeping toilet facilities clean, practicing and teaching water conservation, and advocating to school leadership for better WASH facilities.' },
      { id: 'q6_10', question: 'What percentage of the Earth\'s water is freshwater available for human use?', options: ['About 70%', 'About 30%', 'About 10%', 'Less than 1%'], correct: 3, explanation: 'Less than 1% of Earth\'s water is fresh, liquid water accessible for human use. Most water is saltwater (97%) or frozen in glaciers. This scarcity makes protecting and conserving freshwater extremely important.' }
    ]
  },
  {
    module_id: 7,
    questions: [
      { id: 'q7_1', question: 'How many people still lack access to electricity globally?', options: ['About 75 million', 'About 759 million', 'About 7.5 million', 'About 7.5 billion'], correct: 1, explanation: '759 million people — almost 10% of the global population — still lack access to electricity. Most are in sub-Saharan Africa and South Asia, limiting their access to education, healthcare, and economic opportunities.' },
      { id: 'q7_2', question: 'What are "fossil fuels"?', options: ['Modern, clean energy sources', 'Ancient organic materials (coal, oil, gas) that release greenhouse gases when burned for energy', 'Renewable energy from the sun', 'Energy from plant oils'], correct: 1, explanation: 'Fossil fuels (coal, oil, and natural gas) are ancient organic materials formed over millions of years. Burning them releases CO2 and other greenhouse gases, driving climate change.' },
      { id: 'q7_3', question: 'Why is indoor air pollution from cooking fires particularly dangerous for women and girls?', options: ['It is not more dangerous for them than for others', 'They spend more time near cooking fires, inhaling smoke that causes respiratory disease and death', 'It only affects girls under age 10', 'It mainly causes eye problems'], correct: 1, explanation: 'Women and girls spend more time near cooking fires, inhaling toxic smoke from burning wood, charcoal, and dung. Indoor air pollution from these sources kills 4 million people annually, mostly women and young children.' },
      { id: 'q7_4', question: 'Why does Africa have great potential for solar energy?', options: ['Africa imports solar panels cheaply', 'Africa receives more sunshine than almost any other continent', 'Solar energy works best in cold climates', 'Africa has the most solar engineers'], correct: 1, explanation: 'Africa, especially sub-Saharan Africa, receives some of the highest levels of solar radiation on Earth — making it exceptionally well-suited for solar energy production. This enormous resource is still largely untapped.' },
      { id: 'q7_5', question: 'In Tanzania, when solar panels were installed in rural schools, students\' exam scores improved by how much?', options: ['About 2%', 'About 22%', 'About 50%', 'About 5%'], correct: 1, explanation: 'When solar panels were installed in Tanzania\'s rural schools, girls\' exam scores improved by an average of 22% because students could study for 3-4 extra hours in the evenings instead of stopping at sunset.' },
      { id: 'q7_6', question: 'What are "Solar Mamas" in Kenya\'s Barefoot College program?', options: ['Women who sell solar panels', 'Rural women trained as solar engineers who electrify their villages', 'Mothers who teach children about solar energy', 'Women who collect solar energy data'], correct: 1, explanation: '"Solar Mamas" are rural women — many illiterate — trained by Barefoot College to install and maintain solar systems. They return home and electrify their villages, bringing clean light to thousands of homes.' },
      { id: 'q7_7', question: 'SDG 7 focuses on energy that is...', options: ['Nuclear and coal-based', 'Affordable, reliable, sustainable, and modern', 'Expensive but clean', 'Only from solar and wind'], correct: 1, explanation: 'SDG 7 calls for energy that is affordable (accessible to everyone), reliable (consistent supply), sustainable (from renewable sources that don\'t deplete), and modern (up-to-date technology and infrastructure).' },
      { id: 'q7_8', question: 'What percentage of Rwanda\'s electricity now comes from renewable sources?', options: ['About 10%', 'About 30%', '52%', 'About 80%'], correct: 2, explanation: 'Rwanda now generates 52% of its electricity from renewable sources — primarily solar, hydro, and methane gas from Lake Kivu. This demonstrates that African countries can be leaders in clean energy transition.' },
      { id: 'q7_9', question: 'A girl studies by kerosene lamp every night. What are the risks?', options: ['No significant risks', 'Fire risk, toxic fumes, and eye strain from poor quality light', 'Only the cost of kerosene is a concern', 'Only fire risk'], correct: 1, explanation: 'Kerosene lamps are fire hazards in homes, produce toxic fumes that cause respiratory problems, provide poor quality light that strains eyes, and are expensive — making them a costly and dangerous study option for girls without electricity.' },
      { id: 'q7_10', question: 'How can girls and women accelerate the transition to clean energy?', options: ['They cannot — energy is a technical field for men', 'By learning about clean energy, advocating for it in their communities, and pursuing careers in renewable energy', 'Only by buying expensive solar panels', 'Only by working for energy companies'], correct: 1, explanation: 'Girls and women can accelerate clean energy transition by learning about options, advocating for community clean energy adoption, training as solar technicians and engineers, and leading clean energy businesses.' }
    ]
  },
  {
    module_id: 8,
    questions: [
      { id: 'q8_1', question: 'What is SDG 8 about?', options: ['Quality education for all', 'Decent work and sustainable economic growth', 'Life below water', 'Sustainable cities'], correct: 1, explanation: 'SDG 8 is "Decent Work and Economic Growth" — calling for economies that create meaningful, fairly-paid, safe employment for everyone, while growing in sustainable and inclusive ways.' },
      { id: 'q8_2', question: 'What does "decent work" mean?', options: ['Any job that pays money', 'Work that is productive, provides fair income, offers security, and has safe working conditions', 'Work in an office building', 'Work that only professionals do'], correct: 1, explanation: 'Decent work means productive employment that provides fair income, workplace security, social protection, opportunities for personal development, and freedom for people to express concerns — free from discrimination and exploitation.' },
      { id: 'q8_3', question: 'What is the "gender pay gap"?', options: ['The difference in fashion spending between men and women', 'The fact that women typically earn less than men for the same or comparable work', 'The gap in job availability between genders', 'The difference in education levels between genders'], correct: 1, explanation: 'The gender pay gap is the average difference between men\'s and women\'s earnings. Globally, women earn about 20% less than men for comparable work — reflecting discrimination that must be eliminated for SDG 8.' },
      { id: 'q8_4', question: 'Rebecca Enonchong of Cameroon is significant because she...', options: ['Was the first female president of Cameroon', 'Founded AppsTech, a software company across 50 countries, proving African women can lead global tech businesses', 'Won the Nobel Economics Prize', 'Invented a new type of smartphone'], correct: 1, explanation: 'Rebecca Enonchong founded AppsTech, a successful technology company operating in 50 countries. She demonstrates that African women can lead international technology businesses and is a role model for girls in STEM and entrepreneurship.' },
      { id: 'q8_5', question: 'Why do women entrepreneurs in Africa sometimes struggle to grow their businesses?', options: ['Women are not as business-savvy as men', 'Lack of access to credit, formal business networks, and markets compared to men', 'They prefer smaller businesses', 'African markets don\'t support women\'s products'], correct: 1, explanation: 'Women entrepreneurs in Africa face systemic barriers including difficulty accessing business loans (banks require collateral women often don\'t own), exclusion from male-dominated business networks, and limited market access.' },
      { id: 'q8_6', question: 'What is "M-Pesa" and what SDG does it support?', options: ['A Kenyan food product; SDG 2', 'A mobile money platform that enables financial transactions without bank accounts; SDG 8', 'A solar company; SDG 7', 'A health clinic; SDG 3'], correct: 1, explanation: 'M-Pesa is a mobile money platform created in Kenya that allows people to send money, pay bills, and access financial services via simple phones without bank accounts — dramatically improving economic inclusion and supporting SDG 8.' },
      { id: 'q8_7', question: 'What is "vocational training" and why is it important for girls?', options: ['University-level training; mainly important for professionals', 'Skills training (cooking, tailoring, mechanics, beauty, etc.) that provides practical pathways to employment and income', 'Government job training programs only', 'Training for sports careers'], correct: 1, explanation: 'Vocational training provides practical, job-specific skills that lead directly to employment or self-employment. For girls who may not access university education, vocational skills in fashion, catering, healthcare, or technology provide viable career pathways.' },
      { id: 'q8_8', question: 'If a woman controls her own income, she is MORE likely to...', options: ['Spend it on personal luxuries', 'Invest it in her family\'s education, health, and nutrition', 'Save it all and spend nothing', 'Give it entirely to her husband'], correct: 1, explanation: 'Research consistently shows that women invest a higher proportion of their income in their children\'s education, healthcare, and nutrition compared to men — making women\'s economic empowerment a multiplier for family and community development.' },
      { id: 'q8_9', question: 'What is a "digital skill" and why does it matter for young African women?', options: ['The ability to type fast; mainly useful for office work', 'Proficiency with technology tools (coding, digital marketing, data analysis) that enable access to global job markets', 'Using social media; mainly for entertainment', 'Taking digital photos; a creative skill'], correct: 1, explanation: 'Digital skills — coding, design, digital marketing, data analysis, freelancing — open access to global job markets that transcend local barriers. Young African women with digital skills can earn income from international clients while working from home.' },
      { id: 'q8_10', question: 'What does "sustainable economic growth" mean?', options: ['Economic growth that continues forever regardless of environmental impact', 'Economic growth that improves living standards without depleting natural resources or creating excessive inequality', 'Slow economic growth that takes years', 'Economic growth that only benefits large companies'], correct: 1, explanation: 'Sustainable economic growth means expanding economic output and improving living standards in ways that don\'t exhaust natural resources, damage the environment, or create inequality — ensuring future generations can also prosper.' }
    ]
  },
  {
    module_id: 9,
    questions: [
      { id: 'q9_1', question: 'What does SDG 9 focus on?', options: ['Life below water', 'Industry, Innovation, and Infrastructure', 'No Poverty', 'Reduced Inequalities'], correct: 1, explanation: 'SDG 9 focuses on building resilient infrastructure, promoting inclusive and sustainable industrialization, and fostering innovation — the physical and intellectual foundations of modern economies.' },
      { id: 'q9_2', question: 'What is "infrastructure"?', options: ['Technology companies and startups', 'The basic physical and organizational systems that make a society function — roads, power, internet, water systems', 'Only bridges and highways', 'Government buildings and offices'], correct: 1, explanation: 'Infrastructure is the system of physical structures and networks — roads, railways, power grids, water systems, telecommunications — that enable society and economy to function. Without it, education, health, and economic growth are impossible.' },
      { id: 'q9_3', question: 'How has M-Pesa shown that Africa can "leapfrog" traditional infrastructure?', options: ['By building more banks than any country', 'By providing financial services via mobile phones to millions who never had bank accounts — skipping the need for physical banking infrastructure', 'By printing more money', 'By importing banking technology from Europe'], correct: 1, explanation: 'M-Pesa shows "leapfrogging" — using new technology (mobile phones) to skip over older infrastructure (physical banks) and deliver the same service more accessibly. Africa can adopt modern solutions without replicating older systems.' },
      { id: 'q9_4', question: 'What is "Ushahidi" and what does it demonstrate about African innovation?', options: ['A Swahili word for poverty; demonstrates challenges Africa faces', 'A crisis mapping platform invented in Kenya; demonstrates that Africans can create world-class technology solutions', 'A type of traditional African housing; demonstrates cultural architecture', 'An African currency; demonstrates economic independence'], correct: 1, explanation: 'Ushahidi is a crisis mapping platform created in Kenya after the 2007 elections to map violence reports. It is now used globally in natural disasters and crises, demonstrating that innovative, impactful technology can be invented in Africa for the world.' },
      { id: 'q9_5', question: 'Why is internet access important for girls\' education and opportunities?', options: ['Girls use the internet mainly for social media', 'Internet access connects girls to global knowledge, online learning, job opportunities, and communication tools that expand their horizons', 'Internet is mainly important for boys\' gaming', 'Internet access is a luxury, not a development need'], correct: 1, explanation: 'Internet access gives girls access to the world\'s knowledge, enables online education, connects them to global job markets, and provides tools for learning, creativity, and community building — transforming what is possible for girls in remote areas.' },
      { id: 'q9_6', question: 'What is a "Raspberry Pi" and how has it been used for education in Africa?', options: ['A type of African fruit used for nutrition', 'A small, affordable computer used to create offline learning systems and teach coding in resource-limited schools', 'A video game console popular in African schools', 'A type of solar panel for schools'], correct: 1, explanation: 'A Raspberry Pi is a credit-card-sized, affordable computer (around $35). Educators and innovators in Africa have used them to create offline digital libraries, teach programming, and deliver tech education in schools without reliable internet.' },
      { id: 'q9_7', question: 'What makes innovation "inclusive" in the context of SDG 9?', options: ['When only educated people can use new technologies', 'When innovations benefit and are accessible to all people — including girls, rural communities, disabled people, and the poor', 'When innovations are created by large companies', 'When innovations are free of charge'], correct: 1, explanation: 'Inclusive innovation means that new technologies and systems are designed to be accessible and beneficial to everyone — including marginalized groups. Innovations that only serve the already-privileged fail SDG 9\'s inclusion requirement.' },
      { id: 'q9_8', question: 'The iHub in Nairobi is significant because...', options: ['It is Kenya\'s largest shopping mall', 'It is a technology innovation hub that has supported hundreds of African startups including many women-led companies', 'It is a government headquarters for SDG implementation', 'It is the first African technology university'], correct: 1, explanation: 'iHub in Nairobi has been one of Africa\'s most influential technology innovation spaces — supporting startups, providing co-working spaces, and fostering an ecosystem where African tech entrepreneurs, including many women, have built impactful companies.' },
      { id: 'q9_9', question: 'Why does diverse team including women produce better innovations?', options: ['They don\'t — homogeneous teams are more efficient', 'Diverse teams bring multiple perspectives, experiences, and knowledge, leading to solutions that work for more people', 'Women are more creative than men', 'Diversity slows down innovation'], correct: 1, explanation: 'Research consistently shows that diverse teams — including different genders, backgrounds, and experiences — produce more creative solutions, identify blind spots that homogeneous teams miss, and create products that better serve diverse users.' },
      { id: 'q9_10', question: 'A girl builds a low-cost water purification device from local materials for her village. This is an example of...', options: ['Waste of time since she is not a trained engineer', 'Indigenous, grassroots innovation solving local problems — exactly the spirit of SDG 9', 'Something only valid if patented internationally', 'Copying existing technology'], correct: 1, explanation: 'Local, accessible innovation using available materials to solve real community problems is exactly the kind of inclusive innovation SDG 9 promotes. Formal engineering credentials are not required to be an innovator.' }
    ]
  },
  {
    module_id: 10,
    questions: [
      { id: 'q10_1', question: 'SDG 10 aims to reduce inequality. What type of inequality does it address?', options: ['Only income inequality between people', 'Inequalities within countries AND between countries globally', 'Only racial inequality', 'Only gender inequality'], correct: 1, explanation: 'SDG 10 addresses inequality both within countries (between rich and poor citizens) and between countries (between wealthy and developing nations) — recognizing that both dimensions must be addressed for a fair world.' },
      { id: 'q10_2', question: 'What does "intersectionality" mean for a girl in a rural community with a disability?', options: ['It means she faces only one challenge — her disability', 'She faces multiple overlapping disadvantages (being a girl, rural location, disability) that compound each other', 'It means she automatically receives more government support', 'It has no practical meaning for her daily life'], correct: 1, explanation: 'Intersectionality means that a girl who is female, rural, and disabled faces multiple overlapping disadvantages that reinforce each other — limiting her access to education, healthcare, and opportunities in ways that addressing only one issue cannot solve.' },
      { id: 'q10_3', question: 'What is "social mobility"?', options: ['Using social media to move between social groups', 'The ability to improve one\'s economic and social position through education, hard work, and opportunity', 'Moving from a village to a city', 'Changing your social media profile'], correct: 1, explanation: 'Social mobility means the ability to improve your economic and social standing compared to where you started — moving from poverty to middle class, for example. Education and equal opportunity are key drivers of social mobility.' },
      { id: 'q10_4', question: 'The #EndSARS movement in Nigeria demonstrated that young people can...', options: ['Control the Nigerian economy', 'Use digital advocacy to challenge inequality, police brutality, and hold systems accountable', 'Overthrow governments through social media', 'Solve all inequality through online protests'], correct: 1, explanation: '#EndSARS showed how Nigerian youth — using social media and peaceful protest — could organize a massive national movement challenging police brutality and government accountability, demonstrating the power of youth civic action.' },
      { id: 'q10_5', question: 'In South Africa, girls with disabilities are how many times less likely to attend school than non-disabled peers?', options: ['Twice as likely', '5 times less likely', '10 times less likely', 'About the same likelihood'], correct: 2, explanation: 'In South Africa, girls with disabilities are 10 times less likely to attend school than non-disabled peers — showing how gender and disability create compounding disadvantages that require specific, intersectional solutions.' },
      { id: 'q10_6', question: 'What is "discrimination"?', options: ['Treating people differently based on their skills and qualifications', 'Treating people unfairly based on characteristics like gender, race, disability, or economic status rather than their abilities', 'A way of categorizing people for services', 'Choosing the best candidate for a job'], correct: 1, explanation: 'Discrimination means treating people unfairly or less favorably because of characteristics like gender, race, ethnicity, religion, disability, or economic background — rather than judging them based on their actual abilities and qualities.' },
      { id: 'q10_7', question: 'How does investing in education for the poorest girls help reduce inequality?', options: ['It doesn\'t — education only helps those who are already privileged', 'Educated girls earn more, invest in their children, and contribute to their communities — breaking cycles of inequality across generations', 'It only reduces inequality if they attend top universities', 'It helps individuals but not communities'], correct: 1, explanation: 'When the poorest girls receive quality education, they gain knowledge and skills to earn income, make informed decisions, and invest in their families. These benefits multiply across generations, gradually reducing inherited poverty and inequality.' },
      { id: 'q10_8', question: 'Hindou Oumarou Ibrahim from Chad is significant because she...', options: ['Was the first female president of Chad', 'Represents indigenous and marginalized communities at the United Nations, advocating for their inclusion in climate decisions', 'Won the Nobel Peace Prize', 'Founded a major African NGO'], correct: 1, explanation: 'Hindou Oumarou Ibrahim is a member of the Mbororo indigenous community who has advocated for indigenous peoples\' rights and representation at the UN. She fights for marginalized communities\' inclusion in global decision-making — embodying SDG 10.' },
      { id: 'q10_9', question: 'What is the "Gini coefficient"?', options: ['A measurement of a country\'s GDP growth', 'A measure of income inequality within a country (0 = perfect equality, 1 = extreme inequality)', 'A ranking of countries by gender equality', 'A measurement of educational quality'], correct: 1, explanation: 'The Gini coefficient measures income inequality within a country on a scale of 0 to 1, where 0 means everyone has equal income (perfect equality) and 1 means one person has all the income (extreme inequality). Many African countries have high Gini coefficients.' },
      { id: 'q10_10', question: 'What can YOU do to help reduce inequality in your community?', options: ['Nothing — inequality is too big for individuals to address', 'Speak up against discrimination, support peers facing disadvantage, advocate for equal access to education and resources', 'Only vote when you are old enough', 'Wait for the government to solve it'], correct: 1, explanation: 'Individuals can reduce inequality by challenging discriminatory language and behavior, supporting peers facing disadvantage, advocating for equal access to opportunities, volunteering, and using platforms — social media, school, community — to raise awareness.' }
    ]
  },
  {
    module_id: 11,
    questions: [
      { id: 'q11_1', question: 'By 2050, approximately what fraction of the world\'s population will live in cities?', options: ['About one quarter', 'About one third', 'About two thirds', 'Almost all people'], correct: 2, explanation: 'By 2050, approximately two-thirds of the world\'s population is projected to live in cities. Africa is urbanizing faster than any other continent, making sustainable urban planning critically important for the continent\'s future.' },
      { id: 'q11_2', question: 'What makes a city "sustainable" according to SDG 11?', options: ['Having many tall buildings and highways', 'Being safe, inclusive, resilient, and environmentally sustainable — functioning well for all residents including women and girls', 'Only having solar power', 'Being completely carbon-free immediately'], correct: 1, explanation: 'A sustainable city is safe for all residents (including women and girls), inclusive of marginalized groups, resilient to disasters, and environmentally responsible — growing in ways that don\'t compromise future generations.' },
      { id: 'q11_3', question: 'What percentage of urban Africans live in informal settlements (slums)?', options: ['About 10%', 'About 30%', 'About 60%', 'About 80%'], correct: 2, explanation: 'Approximately 60% of urban Africans live in informal settlements (slums) — communities with poor housing, limited services, and insecure land tenure. Yet these communities are full of creativity, resilience, and innovative solutions.' },
      { id: 'q11_4', question: 'How did young women in Nairobi\'s Kibera improve safety for girls in their community?', options: ['They built security walls', 'They mapped unsafe areas using smartphones, creating a community safety map used to improve lighting and transport', 'They hired more police', 'They moved to a safer neighborhood'], correct: 1, explanation: 'In Kibera, young women mapped unsafe areas using smartphones through a UN Women "Safe Cities" program. Their community safety maps were used to improve street lighting, redesign transport routes, and create safe spaces for women and girls.' },
      { id: 'q11_5', question: 'What is "Umuganda" in Rwanda and how does it help achieve SDG 11?', options: ['A traditional Rwandan dish; helps with food security', 'Monthly community clean-up days where all citizens participate; maintains Kigali as one of Africa\'s cleanest cities', 'A Rwandan musical tradition; builds community cohesion', 'A Rwandan savings program; reduces urban poverty'], correct: 1, explanation: '"Umuganda" is a Rwandan tradition of monthly community work days where all citizens participate in activities like cleaning streets, building community facilities, and planting trees — helping Kigali maintain its status as one of Africa\'s cleanest, most sustainable cities.' },
      { id: 'q11_6', question: 'What is "urban heat island effect"?', options: ['Islands that are hotter than mainland cities', 'The phenomenon where cities are significantly warmer than surrounding rural areas due to concrete, reduced vegetation, and human activity', 'A climate phenomenon only in tropical cities', 'Heating systems in urban buildings'], correct: 1, explanation: 'Urban heat islands occur when cities become significantly warmer than surrounding areas due to concrete, asphalt, reduced vegetation, and heat-generating human activity. This increases energy use, health risks, and discomfort — especially for the poor who lack air conditioning.' },
      { id: 'q11_7', question: 'Why is public transportation safety especially important for girls and women in cities?', options: ['Girls and women use public transport more than men', 'Harassment and violence on public transport is a major barrier that prevents women and girls from accessing education and work', 'Public transport is more expensive for women', 'Girls cannot drive and depend more on buses'], correct: 1, explanation: 'Sexual harassment and violence on public transport is a pervasive barrier for women and girls in African cities, limiting their ability to travel safely to school, work, and services. Safe transport is fundamental to women\'s and girls\' mobility and opportunity.' },
      { id: 'q11_8', question: 'A teenage girl organizes her school to clean blocked drains before rainy season. This action supports SDG 11 by...', options: ['Making the school look cleaner', 'Preventing flooding, protecting her community, and demonstrating that youth can lead community resilience actions', 'Getting the school a clean-up award', 'Practicing environmental science'], correct: 1, explanation: 'Organizing flood prevention through drain cleaning is a concrete community resilience action — reducing disaster risk (an SDG 11 target), protecting homes and school from flood damage, and demonstrating that young people can lead community action.' },
      { id: 'q11_9', question: 'What does "urban resilience" mean?', options: ['City walls that resist attack', 'A city\'s ability to absorb, adapt to, and recover from shocks like floods, droughts, disease outbreaks, and economic crises', 'Strong concrete buildings', 'Large city populations'], correct: 1, explanation: 'Urban resilience is a city\'s capacity to absorb, adapt to, and recover from various shocks and stresses — natural disasters, pandemics, economic downturns — while maintaining essential functions and rebuilding stronger systems.' },
      { id: 'q11_10', question: 'What is one action girls can take to make their community more sustainable?', options: ['Nothing — city planning is only for professional engineers', 'Join or start a community clean-up, advocate for better public spaces for girls, and participate in local governance', 'Leave their community for a more sustainable one', 'Use more electricity to show development'], correct: 1, explanation: 'Girls can make their communities more sustainable by organizing clean-ups, advocating for safe public spaces, documenting and reporting environmental problems, joining youth urban planning consultations, and mobilizing peers to care for their community environment.' }
    ]
  },
  {
    module_id: 12,
    questions: [
      { id: 'q12_1', question: 'What does SDG 12 call for?', options: ['Consuming as much as possible to grow economies', 'Responsible consumption and production patterns that use resources sustainably', 'Banning all manufacturing', 'Only consuming locally produced goods'], correct: 1, explanation: 'SDG 12 calls for changing how we produce goods and services and how we consume them — using fewer resources, reducing waste, and choosing more sustainable options to ensure resources are available for future generations.' },
      { id: 'q12_2', question: 'What is "fast fashion" and why is it problematic?', options: ['Fashion that is trendy and modern; no problems', 'Cheap, quickly-produced clothing discarded after few uses — causing massive environmental pollution and often exploiting workers', 'Fashionable sportswear; slightly problematic for athletes only', 'Fashion shows that happen quickly; problematic for small designers'], correct: 1, explanation: 'Fast fashion produces cheap clothes at high speed, designed to be worn briefly and discarded. This generates enormous waste, uses toxic chemicals, consumes massive water, and often relies on exploited workers (mostly women) in poor conditions.' },
      { id: 'q12_3', question: 'Approximately what fraction of all food produced globally is wasted?', options: ['About one tenth', 'About one quarter', 'About one third', 'About half'], correct: 2, explanation: 'Approximately one-third of all food produced globally — about 1.3 billion tonnes per year — is lost or wasted. This happens at different stages in different contexts: post-harvest and storage losses in Africa, consumer waste in wealthy countries.' },
      { id: 'q12_4', question: 'What is a "circular economy"?', options: ['An economy that goes through cycles of growth and recession', 'An economic system where products are designed to be reused, repaired, or recycled rather than discarded', 'An economy only for developing countries', 'A type of trade that goes in circles between countries'], correct: 1, explanation: 'A circular economy designs out waste by keeping materials in use for as long as possible through repair, reuse, and recycling — contrasting with the linear "take-make-dispose" economy. This reduces resource consumption and waste.' },
      { id: 'q12_5', question: 'Ghana\'s Kantamanto Market receives how much used clothing from wealthy countries weekly?', options: ['1,500 items', '150,000 items', '15 million items', '150 million items'], correct: 2, explanation: 'Kantamanto Market in Accra receives approximately 15 million used clothing items per week — much of it unusable "fashion waste" from wealthy countries. This creates enormous environmental challenges and is an example of wealthy countries exporting their consumption waste to Africa.' },
      { id: 'q12_6', question: 'What is the "Freshbox" innovation from Zimbabwe and how does it support SDG 12?', options: ['A refrigerator company; reduces energy use', 'A clay pot-based evaporative cooler that keeps vegetables fresh for 2 weeks without electricity — reducing food waste', 'A food delivery service; reduces transportation emissions', 'A food packaging company; uses recycled materials'], correct: 1, explanation: 'Freshbox is a low-cost evaporative cooling system made from clay pots that keeps produce fresh for up to 2 weeks without electricity. This innovation by young Zimbabwean women dramatically reduces food waste for market vendors.' },
      { id: 'q12_7', question: 'What is a practical way a student can practice responsible consumption today?', options: ['Stop consuming everything', 'Buy second-hand, repair items before replacing, avoid single-use plastics, and choose products with minimal packaging', 'Only buy expensive sustainable brands', 'Stop wearing fashionable clothes'], correct: 1, explanation: 'Practical responsible consumption includes buying second-hand clothes, repairing broken items, avoiding single-use plastics (bringing reusable bags and bottles), reducing food waste, and choosing products with less packaging.' },
      { id: 'q12_8', question: 'Why does Rwanda\'s plastic bag ban matter for SDG 12?', options: ['It makes Rwanda look good internationally', 'It shows that strong policy can change consumption patterns — Rwanda is now one of Africa\'s cleanest countries partly because of it', 'It only helps tourism', 'It mainly affects foreign tourists'], correct: 1, explanation: 'Rwanda\'s comprehensive plastic bag ban has significantly reduced plastic pollution, making Kigali one of Africa\'s cleanest cities. It demonstrates how government policy combined with cultural change can shift consumption patterns at a national scale.' },
      { id: 'q12_9', question: 'What does it mean to "upcycle" materials?', options: ['Throwing materials up in the air before recycling', 'Transforming waste materials into new products of equal or higher quality and value', 'Sending materials to be recycled at a facility', 'Upgrading products by adding new features'], correct: 1, explanation: 'Upcycling means creatively transforming waste or discarded materials into new products with greater value — like making fashionable bags from discarded tires, or jewelry from old circuit boards. It is both economical and environmentally responsible.' },
      { id: 'q12_10', question: 'How does responsible consumption relate to SDG 13 (Climate Action)?', options: ['They are completely separate goals with no connection', 'Producing and consuming goods causes greenhouse gas emissions — responsible consumption directly reduces carbon footprints and climate impact', 'Consumption only affects local environments', 'Only industrial production affects climate — individual consumption does not matter'], correct: 1, explanation: 'Production and consumption of goods accounts for a significant portion of global greenhouse gas emissions — from manufacturing, transportation, and waste. Responsible consumption directly reduces individual and collective carbon footprints, connecting SDG 12 and SDG 13.' }
    ]
  },
  {
    module_id: 13,
    questions: [
      { id: 'q13_1', question: 'What is the main cause of current climate change?', options: ['Natural climate cycles', 'Greenhouse gases released by burning fossil fuels, deforestation, and industrial activities', 'Volcanic eruptions', 'Variations in the sun\'s brightness'], correct: 1, explanation: 'Current climate change is primarily caused by human activities — especially burning fossil fuels (coal, oil, gas) which releases CO2, deforestation, and industrial agriculture. These activities have increased greenhouse gas concentrations to levels not seen for millions of years.' },
      { id: 'q13_2', question: 'Why is Africa especially vulnerable to climate change despite contributing least to it?', options: ['Africa has no technology to adapt', 'Africa\'s economies depend heavily on climate-sensitive sectors (agriculture, fishing) and have fewer resources to adapt and recover', 'African people don\'t care about climate change', 'Africa has the worst governments for climate planning'], correct: 1, explanation: 'Africa is highly vulnerable because most people depend on rain-fed agriculture and natural resources, economies have fewer resources for adaptation infrastructure, and the continent is geographically exposed to increasing droughts, floods, and heat. Yet Africa contributes only about 4% of global emissions.' },
      { id: 'q13_3', question: 'How did Cyclone Idai in Malawi (2019) affect girls specifically?', options: ['Girls were not specifically affected', 'Girls in affected areas were twice as likely to be married early as families sought economic solutions to food insecurity', 'Girls received more aid than boys', 'Girls recovered faster than boys from the disaster'], correct: 1, explanation: 'After Cyclone Idai destroyed crops in Malawi, some families who lost livelihoods turned to child marriage as a coping strategy, believing daughters\' bride prices could provide income. This shows the direct link between climate disasters and girls\' rights violations.' },
      { id: 'q13_4', question: 'What did Ethiopia achieve on a single day in 2019 related to climate action?', options: ['The first African country to ban fossil fuels', 'Planted 350 million trees in one day — a world record — involving millions of citizens including youth', 'Launched Africa\'s first solar satellite', 'Hosted the world\'s largest climate conference'], correct: 1, explanation: 'On July 29, 2019, Ethiopia planted 350 million trees in a single day — a world record. The effort mobilized millions of citizens, students, and young people across the country as part of the "Green Legacy" initiative to restore degraded land and fight climate change.' },
      { id: 'q13_5', question: 'What is the "greenhouse effect"?', options: ['The effect of building greenhouses for farming', 'The process where gases in the atmosphere trap heat from the sun, warming the Earth beyond its natural temperature', 'Increased plant growth due to higher CO2', 'Energy production from green plants'], correct: 1, explanation: 'The greenhouse effect is the natural process where greenhouse gases (CO2, methane, water vapor) in the atmosphere trap heat from the sun, keeping Earth warm enough for life. Human activities have enhanced this effect by adding excess greenhouse gases, causing dangerous warming.' },
      { id: 'q13_6', question: 'Vanessa Nakate and Hilda Nakabuye are significant because they...', options: ['Are the first African women in space', 'Are African youth who have led powerful climate activism movements connecting climate justice to girls\' rights', 'Are the youngest African government ministers', 'Founded Africa\'s largest environmental NGO'], correct: 1, explanation: 'Vanessa Nakate (Uganda) and Hilda Nakabuye (Uganda) are young climate activists who have organized Fridays for Future strikes in Africa, spoken at international climate conferences, and connected climate justice to gender equality and development in African contexts.' },
      { id: 'q13_7', question: 'What is a "carbon footprint"?', options: ['Footprints left in carbon-rich soil', 'The total amount of greenhouse gases produced by a person, organization, or product — measured in CO2 equivalents', 'Carbon deposits in the atmosphere', 'Marks left by coal mining'], correct: 1, explanation: 'A carbon footprint measures the total greenhouse gas emissions caused by an individual, organization, event, or product — covering energy use, transportation, food choices, and purchases. Understanding and reducing your footprint is a key climate action.' },
      { id: 'q13_8', question: 'How does deforestation contribute to climate change?', options: ['It doesn\'t — trees have nothing to do with climate', 'Trees store carbon; when cut and burned, they release stored carbon AND reduce Earth\'s ability to absorb future CO2', 'It only affects local weather, not global climate', 'It only matters if entire rainforests are cut'], correct: 1, explanation: 'Forests absorb CO2 from the atmosphere and store it in wood and soil. When forests are cut and burned, stored carbon is released as CO2 AND the forest\'s capacity to absorb future emissions is lost — a double climate impact.' },
      { id: 'q13_9', question: 'What is "climate justice"?', options: ['A legal system for trying climate criminals', 'The principle that climate solutions must be fair — addressing that those who caused the least climate damage often suffer the most', 'Only protesting against fossil fuel companies', 'Justice for climate scientists who are persecuted'], correct: 1, explanation: 'Climate justice recognizes that climate change is not just an environmental issue but a justice issue — wealthy countries that caused most emissions must support vulnerable countries (like those in Africa) that suffer disproportionate impacts despite contributing little.' },
      { id: 'q13_10', question: 'What is one direct action a teenager can take for climate action?', options: ['Nothing significant — only governments and companies can address climate change', 'Reduce personal carbon footprint, join or start a climate action group, advocate to school and local authorities for greener policies', 'Wait until they are old enough to vote', 'Move to a cooler country'], correct: 1, explanation: 'Teenagers can take meaningful climate action by reducing their carbon footprint (food choices, energy use, transport), joining climate movements, organizing school sustainability initiatives, and advocating to school administrators, local government, and family members.' }
    ]
  },
  {
    module_id: 14,
    questions: [
      { id: 'q14_1', question: 'What percentage of Earth\'s surface do oceans cover?', options: ['About 50%', 'About 60%', '71%', 'About 85%'], correct: 2, explanation: 'Oceans cover approximately 71% of Earth\'s surface and contain 97% of Earth\'s water. They regulate climate, produce about half of Earth\'s oxygen, absorb CO2, and provide food and livelihoods for billions of people.' },
      { id: 'q14_2', question: 'How many tonnes of plastic enter the ocean every year?', options: ['About 800,000 tonnes', 'About 8 million tonnes', 'About 80 million tonnes', 'About 800 million tonnes'], correct: 1, explanation: 'Approximately 8 million tonnes of plastic enter the ocean each year — equivalent to dumping a garbage truck of plastic into the ocean every minute. This threatens marine life, ecosystems, and eventually enters our food chain as microplastics.' },
      { id: 'q14_3', question: 'What is a "Marine Protected Area" (MPA)?', options: ['A naval base protecting fishing vessels', 'A zone where fishing and development are restricted, allowing marine ecosystems to recover', 'A museum for marine life', 'Protected water for military training'], correct: 1, explanation: 'Marine Protected Areas (MPAs) are designated zones where human activities like fishing and development are restricted or managed, giving marine ecosystems the chance to recover from overexploitation and damage.' },
      { id: 'q14_4', question: 'What is the "blue economy"?', options: ['An economy where all prices are regulated by the government', 'The sustainable use of ocean resources for economic growth, livelihoods, and jobs while preserving ocean health', 'Banking and financial sector (blue = trust)', 'A color-coded economic system'], correct: 1, explanation: 'The blue economy refers to the sustainable use of ocean resources — including fishing, tourism, shipping, and coastal development — in ways that preserve ocean health and support the livelihoods of coastal communities, including women and girls.' },
      { id: 'q14_5', question: 'What are "microplastics" and why are they dangerous?', options: ['Small companies in the plastics industry', 'Tiny plastic particles smaller than 5mm that enter ecosystems and food chains — found in fish, water, and even human blood', 'Biodegradable small plastics', 'Plastic components in electronics'], correct: 1, explanation: 'Microplastics are tiny plastic pieces smaller than 5mm formed when larger plastics break down. They enter water, soil, and the food chain — found in fish, seafood, drinking water, and even in human blood and breast milk. Their health impacts are being actively studied.' },
      { id: 'q14_6', question: 'In Kenya\'s Mombasa Marine National Park, how have communities benefited from marine conservation?', options: ['They have lost income from fishing restrictions with no alternatives', 'Fish populations have recovered, and diving and snorkeling tourism has created new income for local women and youth', 'The park is only beneficial for international researchers', 'Benefits are only realized after 50 years'], correct: 1, explanation: 'In Mombasa Marine National Park, fish populations within the protected area have recovered significantly. Tourism from snorkeling and diving has generated income for local communities — including women who offer services to tourists — showing that conservation and livelihoods can go together.' },
      { id: 'q14_7', question: 'What is "ocean acidification" and what causes it?', options: ['Acid rain falling into the ocean from industrial pollution', 'Oceans becoming more acidic as they absorb CO2 from the atmosphere — threatening shellfish, coral reefs, and marine ecosystems', 'Natural acid produced by marine animals', 'Volcanic activity on the ocean floor'], correct: 1, explanation: 'Ocean acidification occurs as oceans absorb CO2 from the atmosphere. CO2 dissolved in seawater forms carbonic acid, lowering pH. This threatens organisms that build shells and skeletons from calcium carbonate — especially corals and shellfish — with cascading effects on marine food chains.' },
      { id: 'q14_8', question: 'What role do women play in coastal fishing communities in Ghana?', options: ['Women are excluded from fishing roles', 'Women control fish processing, drying, and marketing — making them key economic players in the fishing value chain', 'Women only cook the fish caught by men', 'Women own all the fishing boats'], correct: 1, explanation: 'In Ghana\'s coastal communities, women "fish processors" (fante traders) have traditionally controlled the processing, drying, smoking, and trading of fish — playing crucial economic roles in the fishing value chain that are threatened by declining fish stocks.' },
      { id: 'q14_9', question: 'What can students in landlocked countries do to protect oceans?', options: ['Nothing — oceans are far away and irrelevant', 'Reduce plastic use, avoid products from unsustainable fishing, and advocate for clean river policies since rivers carry pollution to oceans', 'Only go to the coast to volunteer', 'Study marine biology at university'], correct: 1, explanation: 'Even landlocked communities contribute to ocean health. Plastics and pollutants from inland areas travel through rivers to the sea. Reducing plastic use, keeping rivers clean, and advocating for clean water policies all protect ocean health from any location.' },
      { id: 'q14_10', question: 'What is mangrove restoration and why is it important?', options: ['Growing mango trees near the ocean', 'Replanting mangrove forests that protect coastlines from erosion, store carbon, and provide nursery habitat for fish', 'A type of coastal fishing technique', 'Clearing mangroves for coastal development'], correct: 1, explanation: 'Mangrove forests are coastal ecosystems that protect shorelines from erosion and storms, store significant amounts of carbon, provide nursery habitat for fish, and support coastal livelihoods. Mangrove restoration reverses damage from deforestation and development.' }
    ]
  },
  {
    module_id: 15,
    questions: [
      { id: 'q15_1', question: 'How much forest does Africa lose every year?', options: ['About 340,000 hectares', 'About 3.4 million hectares', 'About 34 million hectares', 'About 340 million hectares'], correct: 1, explanation: 'Africa loses approximately 3.4 million hectares of forest per year — more than any other continent. This deforestation reduces biodiversity, increases carbon emissions, disrupts water cycles, and degrades land that communities depend on.' },
      { id: 'q15_2', question: 'Why is Africa\'s Congo Basin rainforest important for global climate?', options: ['It is important mainly for Congo\'s economy', 'It is the world\'s second-largest rainforest and critical carbon sink, absorbing millions of tonnes of CO2 annually', 'It produces Africa\'s largest timber exports', 'It is mainly important for regional rainfall only'], correct: 1, explanation: 'The Congo Basin rainforest is the world\'s second-largest tropical rainforest and a critical global carbon sink — absorbing carbon dioxide from the atmosphere. Its destruction would release massive amounts of CO2 and destabilize climate systems well beyond Africa.' },
      { id: 'q15_3', question: 'What is the "zaï" technique used in Burkina Faso?', options: ['A traditional dance performed at planting time', 'An ancient technique of digging small planting pits with organic matter to restore degraded land', 'A chemical fertilizer application method', 'A water irrigation system'], correct: 1, explanation: 'Zaï is an ancient Sahelian farming technique where small pits are hand-dug in dry, compacted soil and filled with organic matter (compost, manure) before planting. This collects rainwater and improves soil fertility, transforming barren land into productive farms.' },
      { id: 'q15_4', question: 'What is "biodiversity" and why does it matter?', options: ['The variety of technology available in a country', 'The variety of life on Earth — plants, animals, fungi, microorganisms — and the ecosystems they form, providing essential services', 'The diversity of languages spoken in a region', 'Economic diversity within a country'], correct: 1, explanation: 'Biodiversity refers to the variety of all living organisms — from genes to species to ecosystems. It provides essential services including food, medicine, clean water, pollination, and climate regulation. Losing biodiversity threatens the systems all life, including humans, depends on.' },
      { id: 'q15_5', question: 'Wangari Maathai\'s Green Belt Movement has planted how many trees in Kenya?', options: ['About 5 million trees', 'About 10 million trees', 'Over 51 million trees', 'About 100 million trees'], correct: 2, explanation: 'The Green Belt Movement, founded by Nobel Prize winner Wangari Maathai, has planted over 51 million trees across Kenya by empowering rural women and girls to run tree nurseries and lead reforestation. This has restored watersheds, reduced erosion, and provided income for thousands of women.' },
      { id: 'q15_6', question: 'What is "desertification"?', options: ['Creating desert-themed parks', 'The process by which fertile land becomes desert through drought, deforestation, and poor land management', 'Building cities in desert regions', 'Mining sand in desert areas'], correct: 1, explanation: 'Desertification is the process by which land that was once fertile and productive becomes increasingly dry, barren, and desert-like. It is caused by drought, overgrazing, deforestation, and poor agricultural practices. It threatens food security and livelihoods for millions in Africa.' },
      { id: 'q15_7', question: 'Leah Namugerwa of Uganda is known for...', options: ['Being the youngest MP in Uganda', 'Starting a "trees for birthday" campaign that has planted over 100,000 trees in Uganda', 'Founding the Green Belt Movement', 'Winning an Olympic gold medal'], correct: 1, explanation: 'Leah Namugerwa, a Ugandan climate activist, started asking for trees instead of birthday gifts and challenged others to do the same. Her campaign has inspired thousands of Ugandans to plant trees, contributing to over 100,000 trees planted through her initiative.' },
      { id: 'q15_8', question: 'What is "poaching" and why is it a major threat to African wildlife?', options: ['Cooking eggs in hot water; not related to wildlife', 'Illegal hunting of protected animals for profit — driving many African species toward extinction', 'Moving animals from one national park to another', 'Scientific study of animal behavior'], correct: 1, explanation: 'Poaching is illegal hunting of protected wildlife — often for ivory (elephants), rhino horn, bushmeat, and rare animals sold as pets. It has driven many African species to endangered or critically endangered status, threatening biodiversity and the tourism income communities depend on.' },
      { id: 'q15_9', question: 'How does healthy land connect to girls\' education?', options: ['There is no connection', 'When land is degraded and crops fail, girls are first pulled from school to fetch water, earn money, or marry early', 'Healthy land means girls have more homework about agriculture', 'Girls study better on healthy land'], correct: 1, explanation: 'When drought or land degradation reduces crop yields, families in crisis often pull girls out of school first to contribute to household survival — through water collection, domestic labor, or earning money. Healthy, productive land is therefore foundational to girls\' educational security.' },
      { id: 'q15_10', question: 'What is ONE thing a student can do to protect life on land?', options: ['Nothing meaningful as an individual', 'Plant native trees, avoid products linked to deforestation, participate in land conservation activities, and educate others', 'Only study environmental science at university', 'Move to a less environmentally damaged country'], correct: 1, explanation: 'Students can protect life on land by planting and caring for native trees, choosing products that don\'t contribute to deforestation (like certified palm oil, sustainably sourced wood products), joining local conservation initiatives, and educating their families and peers.' }
    ]
  },
  {
    module_id: 16,
    questions: [
      { id: 'q16_1', question: 'Why is peace and justice foundational for achieving all other SDGs?', options: ['It is not — other SDGs can be achieved without peace', 'Without peace and functioning institutions, schools are destroyed, resources are diverted, and rights cannot be protected — making other SDGs impossible to achieve', 'It is only important for SDGs about governance', 'Peace is important but not required for economic SDGs'], correct: 1, explanation: 'Conflict destroys infrastructure, displaces communities, diverts resources to military spending, and creates conditions where rights cannot be protected. Without peace and strong institutions, none of the other SDGs — education, health, economic growth — can be sustainably achieved.' },
      { id: 'q16_2', question: 'How are girls specifically affected by armed conflict?', options: ['Girls are not specifically targeted in conflicts', 'Schools are destroyed, girls face sexual violence, child marriage rates increase, and girls\' needs are often overlooked in reconstruction', 'Girls are safer than boys in conflict because they are noncombatants', 'Girls face the same challenges as boys in conflict'], correct: 1, explanation: 'Armed conflict specifically harms girls through school destruction (disrupting education), heightened risk of sexual violence (used as weapon of war), increased rates of child marriage (as coping mechanism), and exclusion from post-conflict reconstruction planning.' },
      { id: 'q16_3', question: 'How did the Women of Liberia Mass Action for Peace end the civil war in 2003?', options: ['They organized a military coup', 'Through nonviolent action — praying, singing, and refusing to move until warlords negotiated peace', 'They appealed to foreign governments for military intervention', 'They negotiated directly with the opposing military forces'], correct: 1, explanation: 'Leymah Gbowee and the women of Liberia used nonviolent tactics — prayer, song, sit-ins, and refusing to leave peace negotiations — to force Liberia\'s warlords to reach a peace agreement. Their courage ended a devastating civil war that had killed thousands.' },
      { id: 'q16_4', question: 'What is "corruption" and how does it harm girls and women?', options: ['Disagreement between government officials; mainly affects governance', 'Dishonest use of power for personal gain — it diverts resources from education, health, and social services that girls and women depend on', 'Business competition practices; mainly affects companies', 'Political debate and disagreement; normal in democracies'], correct: 1, explanation: 'Corruption — bribery, theft of public funds, nepotism — steals money from schools, clinics, and services. It means that scholarships go to connected people instead of deserving girls, that school buildings aren\'t built, and that protections for girls aren\'t enforced.' },
      { id: 'q16_5', question: 'What are "civic rights"?', options: ['Rights to own property and businesses', 'Rights that citizens have in relation to the state — to vote, to free speech, to a fair trial, to peaceful assembly', 'Rights only for educated adults', 'Rights given by religious communities'], correct: 1, explanation: 'Civic rights (or civil rights) are the rights citizens have in relation to their government — including the right to vote, to free speech, to religious freedom, to peaceful protest, and to a fair trial. These rights are fundamental to democratic societies and must be protected for all.' },
      { id: 'q16_6', question: 'Ugandan students who reported their school\'s stolen feeding program funds demonstrated...', options: ['That young people should not get involved in corruption issues', 'That youth can actively fight corruption by using available reporting channels — recovering stolen resources for their community', 'That corruption is too complex for students to address', 'That reporting corruption is dangerous and should be avoided'], correct: 1, explanation: 'The Ugandan students who reported stolen school feeding funds through a government transparency hotline showed that young people can effectively fight corruption. Their action triggered an investigation, recovered stolen money, and led to accountability.' },
      { id: 'q16_7', question: 'What does "rule of law" mean?', options: ['Government officials following their own personal rules', 'The principle that all people, including government officials, are equally subject to clearly defined, publicly enforced laws', 'Only religious law applying to all citizens', 'Laws that only apply during special situations'], correct: 1, explanation: 'Rule of law means that laws are clear, public, and equally enforced for everyone — including the most powerful government officials. Without rule of law, the powerful can act with impunity while the powerless (often women and girls) receive no protection.' },
      { id: 'q16_8', question: 'Leymah Gbowee won the Nobel Peace Prize for...', options: ['Writing a book about peace in Liberia', 'Organizing nonviolent women\'s movements that helped end Liberia\'s civil war and advance women\'s rights', 'Serving as Liberia\'s president', 'Developing peace education curriculum for African schools'], correct: 1, explanation: 'Leymah Gbowee won the 2011 Nobel Peace Prize for her work leading the Women of Liberia Mass Action for Peace — organizing Christian and Muslim women in nonviolent protest that helped end Liberia\'s devastating civil war in 2003.' },
      { id: 'q16_9', question: 'What does SDG 16 say about access to justice?', options: ['Justice is only for those who can afford lawyers', 'Access to justice for all — meaning everyone can access legal protection and recourse regardless of wealth or status', 'Justice should be primarily administered by community elders', 'International courts are the primary justice mechanism'], correct: 1, explanation: 'SDG 16 specifically calls for "access to justice for all" — meaning that legal systems must be accessible, affordable, and fair for everyone, including poor women, girls, and marginalized communities who often face the greatest barriers to justice.' },
      { id: 'q16_10', question: 'How can girls participate in civic life and governance?', options: ['Girls should wait until adulthood to participate in governance', 'By joining student councils, attending community meetings, writing to officials, voting when eligible, and holding leadership positions in youth organizations', 'Only by becoming politicians', 'Only by following news about politics'], correct: 1, explanation: 'Girls can participate in governance at every level — through school student councils, community meetings, writing letters to officials, advocating on social media, volunteering for campaigns, and taking leadership roles in youth organizations. Every participation builds skills and confidence for future leadership.' }
    ]
  },
  {
    module_id: 17,
    questions: [
      { id: 'q17_1', question: 'What is SDG 17 about?', options: ['Peace and strong institutions', 'Partnerships for the Goals — the idea that achieving all SDGs requires cooperation across organizations, governments, and people', 'Protecting life on land', 'Responsible consumption'], correct: 1, explanation: 'SDG 17 is about partnerships — recognizing that achieving the other 16 SDGs requires unprecedented collaboration between governments, businesses, civil society, communities, and individuals at local, national, and global levels.' },
      { id: 'q17_2', question: 'What does "Official Development Assistance" (ODA) mean in the context of SDG 17?', options: ['Assistance given by developing countries to others', 'Aid and financial resources provided by wealthy countries to support development in lower-income countries', 'Military assistance between countries', 'Technical training programs for officials'], correct: 1, explanation: 'Official Development Assistance (ODA) is financial aid given by wealthy governments to developing countries and international organizations to support development, humanitarian work, and governance improvements. SDG 17 calls for increased and more effective ODA.' },
      { id: 'q17_3', question: 'What makes a partnership "effective" according to SDG 17 principles?', options: ['Having the most money and biggest organizations involved', 'Mutual respect, shared goals, clear roles, transparency, accountability, and combining diverse strengths toward common goals', 'Being organized by international organizations rather than local communities', 'Involving governments exclusively'], correct: 1, explanation: 'Effective partnerships for the SDGs are built on mutual respect for all partners, shared goals, clearly defined roles, transparency in decisions and finances, accountability for results, and bringing together complementary strengths — including local community knowledge and global resources.' },
      { id: 'q17_4', question: 'What is the African Union\'s "Agenda 2063"?', options: ['A plan to unite all African countries into one nation by 2063', 'Africa\'s own 50-year development vision for a peaceful, prosperous, and integrated continent designed by Africans for Africans', 'A plan to host the World Cup in Africa in 2063', 'A trade agreement between 20 African nations'], correct: 1, explanation: 'Agenda 2063 is the African Union\'s strategic framework for transforming Africa over 50 years — a vision of a peaceful, prosperous, and integrated Africa developed by Africans. It represents African ownership of Africa\'s development agenda rather than dependence on external prescriptions.' },
      { id: 'q17_5', question: 'How does technology enable partnerships for the SDGs?', options: ['Only by providing internet connections', 'By enabling communication, data sharing, and collaboration across distances — allowing activists in rural Africa to work with global partners', 'Only useful for large organizations with big budgets', 'Technology creates more barriers than connections for developing countries'], correct: 1, explanation: 'Technology — internet, mobile phones, social media, video calls, open data platforms — enables people across distances and economic levels to share knowledge, coordinate action, advocate globally, and build partnerships that would have been impossible without digital tools.' },
      { id: 'q17_6', question: 'Why must youth be partners in the SDGs rather than just beneficiaries of programs?', options: ['Youth do not have the experience needed to contribute to SDG implementation', 'Young people make up the majority of Africa\'s population, have unique perspectives, and will live with SDG decisions longest — their genuine partnership is essential for effective and lasting solutions', 'Youth should focus on education and leave SDG work to adults', 'Youth participation is symbolic — actual decision-making should stay with experts'], correct: 1, explanation: 'With Africa\'s median age around 20, young people are not just the future — they are the majority present. Their lived experience, creativity, digital fluency, and long-term stake in SDG outcomes make their genuine partnership (not just token consultation) essential for effective SDG implementation.' },
      { id: 'q17_7', question: 'What is the "African Youth SDGs Summit" and what has it achieved?', options: ['A competition where youth present SDG ideas to win prizes', 'An annual youth-led conference that produces African youth commitments which have influenced national development plans in 15 countries', 'A summit organized by African governments with some youth speakers', 'An international event held in New York about African SDG progress'], correct: 1, explanation: 'The African Youth SDGs Summit is led entirely by young Africans, bringing youth leaders from every African country to share solutions, build partnerships, and advocate directly to governments. Its youth-led commitments have influenced national development plans in 15 countries.' },
      { id: 'q17_8', question: 'What does "South-South cooperation" mean in SDG 17?', options: ['Cooperation between countries in the Southern Hemisphere only', 'Development partnerships between developing countries sharing knowledge, resources, and solutions with each other', 'Trade between South Africa and southern African countries', 'A cooperation between Southern Europe and Northern Africa'], correct: 1, explanation: 'South-South cooperation refers to partnerships between developing countries (the "Global South") sharing knowledge, technology, resources, and solutions with each other — rather than always depending on partnerships with wealthy northern countries.' },
      { id: 'q17_9', question: 'As a Bloom Girl, you are part of which SDG 17 partnership?', options: ['No specific partnership — you are a student learning independently', 'A growing global community of young African girls committed to knowledge, leadership, and action on the 17 SDGs', 'A partnership with international NGOs who fund your education', 'A partnership only with your school and local community'], correct: 1, explanation: 'By completing Bloom Girl Africa, you join a community of empowered, SDG-educated African girls — a network of change-makers who share knowledge, inspire each other, and collectively amplify their impact. You are both a product of and a partner in this mission.' },
      { id: 'q17_10', question: 'After completing all 17 SDG modules, what is the MOST important next step for a Bloom Girl?', options: ['Rest and celebrate the achievement — the learning is done', 'Take action — choose one SDG, identify a local challenge, find partners, and take concrete steps to make a difference in your community', 'Share the certificate on social media only', 'Wait for a job opportunity related to the SDGs to apply the knowledge'], correct: 1, explanation: 'The purpose of SDG education is action. The most important next step is to translate knowledge into change — choosing a specific SDG area, identifying a real community challenge, building partnerships, and taking concrete steps. Your education becomes meaningful through what you do with it.' }
    ]
  }
]

export function getQuizByModuleId(moduleId: number): QuizSet | undefined {
  return QUIZ_QUESTIONS.find(q => q.module_id === moduleId)
}

export function shuffleQuestions(questions: QuizSet['questions'], count = 10) {
  const shuffled = [...questions].sort(() => Math.random() - 0.5)
  return shuffled.slice(0, Math.min(count, shuffled.length))
}
